import{c as n,Q as s,j as e,m as t}from"./chunks/framework.BI6u8GL6.js";const h=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1783201272000}'),p={name:"guide/architecture.md"};function i(l,a,r,o,c,d){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>This document describes the internal architecture of MyJpa-Plus, including module relationships, data flow, and security defense layers.</p><h2 id="module-map" tabindex="-1">Module Map <a class="header-anchor" href="#module-map" aria-label="Permalink to &quot;Module Map&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>com.zsubera.jpa</span></span>
<span class="line"><span>├── spec/              # Query specification builder (core)</span></span>
<span class="line"><span>│   ├── SFunction        — Serializable functional interface for lambda property extraction</span></span>
<span class="line"><span>│   ├── QuerySpec        — Main entry point (implements Specification&amp;lt;T&amp;gt; + ConditionBuilder)</span></span>
<span class="line"><span>│   ├── SubQuerySpec     — EXISTS/IN subquery builder (eager evaluation)</span></span>
<span class="line"><span>│   ├── CteSpec          — CTE builder (native SQL)</span></span>
<span class="line"><span>│   ├── ConditionBuilder — 40+ default condition methods (lazy evaluation)</span></span>
<span class="line"><span>│   ├── ConditionNode    — Sealed AST hierarchy (11 node types)</span></span>
<span class="line"><span>│   ├── NodeResolver     — AST → JPA Predicate resolver</span></span>
<span class="line"><span>│   ├── PredicateHelper  — Shared static predicate builder</span></span>
<span class="line"><span>│   ├── FunctionWhitelist — Function whitelist (startup ConcurrentHashMap → frozen snapshot)</span></span>
<span class="line"><span>│   ├── Spec             — Specification combinator (and/or/not static methods)</span></span>
<span class="line"><span>│   ├── QueryAggregates  — count/sum/avg/max/min expression factory</span></span>
<span class="line"><span>│   ├── JoinGroup / OrJoinGroup / OrGroup / NotGroup — Condition grouping builders</span></span>
<span class="line"><span>│   ├── BulkConditionSupport — Bulk operation condition method interface</span></span>
<span class="line"><span>│   └── QueryHavingSupport / QueryConditionSupport / QueryCompositionSupport</span></span>
<span class="line"><span>│       / QuerySubQuerySupport / QueryJoinSupport / QueryAggregateSupport</span></span>
<span class="line"><span>│       / QueryOrderBySupport — QuerySpec decomposition helpers</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── update/            # Bulk operations</span></span>
<span class="line"><span>│   ├── UpdateSpec       — Bulk UPDATE builder</span></span>
<span class="line"><span>│   ├── DeleteSpec       — Bulk DELETE builder</span></span>
<span class="line"><span>│   ├── MergeSpec        — UPSERT/MERGE builder (4 dialects + multi-row batch)</span></span>
<span class="line"><span>│   ├── AbstractBulkOperationSpec — Bulk operation condition tree + row limit checks</span></span>
<span class="line"><span>│   ├── OrConditionBuilder — OR condition group builder</span></span>
<span class="line"><span>│   ├── BulkTransactionHelper — Shared transaction management utility</span></span>
<span class="line"><span>│   ├── AuditUtils       — Audit logging and stack trace extraction</span></span>
<span class="line"><span>│   ├── DialectDetector  — Auto-detect database dialect from EntityManager</span></span>
<span class="line"><span>│   ├── DialectStrategy  — Dialect-specific UPSERT SQL generation SPI</span></span>
<span class="line"><span>│   ├── AbstractDialectStrategy — Shared quoting logic</span></span>
<span class="line"><span>│   ├── MysqlDialect / PostgresDialect / OracleDialect / SqlServerDialect</span></span>
<span class="line"><span>│   └── EntityFieldExtractor — Reflect entity fields → column name/value pairs</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── template/          # Query execution &amp; caching</span></span>
<span class="line"><span>│   ├── MyJpaTemplate    — Main query/bulk template (Spring Bean)</span></span>
<span class="line"><span>│   ├── MyJpaTemplateOperations — Template operations interface (lambda query overloads)</span></span>
<span class="line"><span>│   ├── QueryCacheManager — ConcurrentHashMap-based TTL cache (implements CacheAdapter)</span></span>
<span class="line"><span>│   ├── CacheAdapter     — Pluggable cache backend SPI</span></span>
<span class="line"><span>│   ├── CacheInvalidationListener — Auto-evict cache after entity modifications</span></span>
<span class="line"><span>│   ├── BulkOperationTemplate — Bulk execution with transaction management</span></span>
<span class="line"><span>│   ├── BatchSaveTemplate — Batch persist/merge with flush/clear cycles</span></span>
<span class="line"><span>│   ├── KeysetPaginationHelper — Keyset (cursor) pagination helper</span></span>
<span class="line"><span>│   ├── QueryBuildHelper — Query construction helper (Specification merge, count queries)</span></span>
<span class="line"><span>│   └── DeepPaginationGuard — Deep pagination protection</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── projection/        # DTO &amp; Tuple projection (integrated into QuerySpec)</span></span>
<span class="line"><span>│   └── QueryProjectionSupport — select()/selectAs()/asDto() execution via MyJpaTemplate</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── repository/        # Extended Spring Data Repository</span></span>
<span class="line"><span>│   ├── MyJpaRepository   — Repository interface with Lambda DSL</span></span>
<span class="line"><span>│   ├── DefaultMyJpaRepository — Base implementation with soft delete</span></span>
<span class="line"><span>│   ├── MyJpaRepositoryFactoryBean — Custom RepositoryFactoryBean</span></span>
<span class="line"><span>│   ├── SoftDeleteContext  — @IgnoreSoftDelete ThreadLocal stack</span></span>
<span class="line"><span>│   ├── EntityManagerHelper / EntityManagerResolver — Multi-datasource resolver</span></span>
<span class="line"><span>│   ├── IgnoreSoftDeleteAdvisor — @IgnoreSoftDelete AOP advice</span></span>
<span class="line"><span>│   └── OptimisticLockRetryAdvisor — @RetryOnOptimisticLock AOP advice</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── softdelete/        # Soft delete features</span></span>
<span class="line"><span>│   ├── SoftDeleteHelper  — Soft delete field/annotation/Specification cache</span></span>
<span class="line"><span>│   └── SoftDeleteBulkExecutor — Bulk delete via native SQL / CriteriaUpdate</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── annotation/        # Custom annotations</span></span>
<span class="line"><span>│   ├── @SoftDelete       — Mark field as soft delete flag</span></span>
<span class="line"><span>│   ├── @IgnoreSoftDelete — Disable automatic soft delete filtering</span></span>
<span class="line"><span>│   ├── @Encrypt          — AES/GCM transparent encryption</span></span>
<span class="line"><span>│   ├── @Mask             — JSON output masking</span></span>
<span class="line"><span>│   └── @RetryOnOptimisticLock — AOP annotation with exponential backoff retry</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── converter/         # Type converters</span></span>
<span class="line"><span>│   ├── @CodeEnum / @CodeEnumValue — Code-based enum annotations</span></span>
<span class="line"><span>│   ├── CodeEnumType      — Hibernate UserType for code-based enums</span></span>
<span class="line"><span>│   ├── CodeEnumHelper    — Enum code resolution helper</span></span>
<span class="line"><span>│   ├── EncryptConverter  — AES/GCM AttributeConverter</span></span>
<span class="line"><span>│   ├── EncryptionKeyManager — PBKDF2 key derivation, multi-version rotation</span></span>
<span class="line"><span>│   └── MaskSerializer    — Jackson serializer for @Mask</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── monitor/           # SQL monitoring</span></span>
<span class="line"><span>│   ├── SlowQueryDataSourceProxy — JDBC proxy-based slow query detection</span></span>
<span class="line"><span>│   ├── SlowQueryDataSourceProxyPostProcessor — DataSource post-processing proxy</span></span>
<span class="line"><span>│   ├── QueryMetricsCollector — Singleton metrics (count, average, max)</span></span>
<span class="line"><span>│   ├── SqlSlowQueryInterceptor — Hibernate StatementInspector slow query detection (deprecated)</span></span>
<span class="line"><span>│   ├── SqlSanitizer     — Remove sensitive data from SQL logs</span></span>
<span class="line"><span>│   └── SlowQueryListener — Slow query event listener interface</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── autoconfigure/     # Spring Boot auto-configuration</span></span>
<span class="line"><span>│   ├── MyJpaPlusAutoConfiguration — Main @AutoConfiguration</span></span>
<span class="line"><span>│   ├── MyJpaPlusGlobalConfig — Global config bean</span></span>
<span class="line"><span>│   ├── MyJpaPlusProperties — @ConfigurationProperties</span></span>
<span class="line"><span>│   ├── GlobalConfigHolder — Centralized config with volatile fields</span></span>
<span class="line"><span>│   ├── EnvironmentHelper — Environment detection utility</span></span>
<span class="line"><span>│   └── SoftDeleteFilterBean — Soft delete JPA Specification injection</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── codegen/           # Code generation</span></span>
<span class="line"><span>│   └── EntityCodeGenerator — Generate JPA entity source from table metadata</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── exception/         # Custom exceptions</span></span>
<span class="line"><span>│   ├── MyJpaPlusException — Base exception with ErrorCode + context cleanup</span></span>
<span class="line"><span>│   ├── QueryBuildException / BulkOperationException / DataAccessException</span></span>
<span class="line"><span>│   └── SecurityViolationException / TimeoutException</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── util/              # Shared utilities</span></span>
<span class="line"><span>    ├── LambdaUtils        — SerializedLambda → property name extraction</span></span>
<span class="line"><span>    ├── IdentifierValidator — SQL identifier validation + Unicode homoglyph detection</span></span>
<span class="line"><span>    ├── InClauseBuilder    — IN/NOT IN clause auto-batching</span></span>
<span class="line"><span>    ├── SampledEvictionCache — ConcurrentHashMap-based sample eviction cache</span></span>
<span class="line"><span>    ├── CacheEvictionHelper — L1 cache selective eviction</span></span>
<span class="line"><span>    ├── PageableHelper     — Pagination parameter helper</span></span>
<span class="line"><span>    └── EntityClassResolver / StringHelper / EntityGraphHelper</span></span></code></pre></div><h2 id="data-flow-lambda-query-execution" tabindex="-1">Data Flow: Lambda Query Execution <a class="header-anchor" href="#data-flow-lambda-query-execution" aria-label="Permalink to &quot;Data Flow: Lambda Query Execution&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Code                   Library                        JPA Provider</span></span>
<span class="line"><span>─────────                   ───────                        ────────────</span></span>
<span class="line"><span>repository.findAll(s -&gt;     QuerySpec.of(consumer)</span></span>
<span class="line"><span>  s.eq(User::getName,       │</span></span>
<span class="line"><span>    &quot;John&quot;)                 │</span></span>
<span class="line"><span>                            │ LambdaUtils.resolveProperty(User::getName)</span></span>
<span class="line"><span>                            │ → SerializedLambda → &quot;name&quot;</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ QuerySpec.eq(&quot;name&quot;, &quot;John&quot;)</span></span>
<span class="line"><span>                            │ → Append SimpleNode to condition list</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ QuerySpec.toPredicate(root, cb, query)</span></span>
<span class="line"><span>                            │ → NodeResolver.resolve(conditionTree)</span></span>
<span class="line"><span>                            │ → Recursively traverse ConditionNode tree</span></span>
<span class="line"><span>                            │ → SimpleNode.resolve() → cb.equal(root.get(&quot;name&quot;), &quot;John&quot;)</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ Return JPA Predicate</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ JPA CriteriaQuery.where(predicate)</span></span>
<span class="line"><span>                            └──────────────────────────────────→ SELECT * FROM users WHERE name = &#39;John&#39;</span></span></code></pre></div><h2 id="data-flow-single-row-upsert" tabindex="-1">Data Flow: Single-row UPSERT <a class="header-anchor" href="#data-flow-single-row-upsert" aria-label="Permalink to &quot;Data Flow: Single-row UPSERT&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MergeSpec.withEntity(user)</span></span>
<span class="line"><span>  .onConflict(User::getEmail)</span></span>
<span class="line"><span>  .updateOnConflict(User::getName)</span></span>
<span class="line"><span>  .execute(em)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── DialectDetector.detectDialect(em)</span></span>
<span class="line"><span>    │   ├── Priority 1: JDBC URL property</span></span>
<span class="line"><span>    │   ├── Priority 2: Connection.getMetaData().getDatabaseProductName()</span></span>
<span class="line"><span>    │   ├── Priority 3: Hibernate Session reflection</span></span>
<span class="line"><span>    │   └── Priority 4: System property myjpa-plus.dialect</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── DialectStrategy.buildUpsertSql(...)</span></span>
<span class="line"><span>    │   ├── MysqlDialect:     INSERT INTO t (...) VALUES (...) ON DUPLICATE KEY UPDATE col = VALUES(col)</span></span>
<span class="line"><span>    │   ├── PostgresDialect:  INSERT INTO t (...) VALUES (...) ON CONFLICT (...) DO UPDATE SET col = EXCLUDED.col</span></span>
<span class="line"><span>    │   ├── OracleDialect:    MERGE INTO t USING (SELECT ? AS col FROM DUAL) ON (...) WHEN NOT MATCHED ...</span></span>
<span class="line"><span>    │   └── SqlServerDialect: MERGE INTO t USING (VALUES (?)) AS new_row(col) ON (...) WHEN NOT MATCHED ...</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── em.createNativeQuery(sql).executeUpdate()</span></span></code></pre></div><h2 id="data-flow-multi-row-batch-upsert" tabindex="-1">Data Flow: Multi-row Batch UPSERT <a class="header-anchor" href="#data-flow-multi-row-batch-upsert" aria-label="Permalink to &quot;Data Flow: Multi-row Batch UPSERT&quot;">​</a></h2><p>When <code>MergeSpec.executeBatch()</code> detects batch mode support via <code>supportsBatchUpsert()</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MergeSpec.executeBatch([user1, user2, user3], em)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── DialectStrategy.supportsBatchUpsert()? → true</span></span>
<span class="line"><span>  │   ├── MysqlDialect:     true</span></span>
<span class="line"><span>  │   └── PostgresDialect:  true</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── EntityFieldExtractor.extractFieldValues() per entity</span></span>
<span class="line"><span>  │   → [user1: (name→&quot;A&quot;, email→&quot;a@x&quot;), user2: (name→&quot;B&quot;, email→&quot;b@x&quot;), ...]</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── DialectStrategy.buildBatchUpsertSql(...)</span></span>
<span class="line"><span>  │   ├── MysqlDialect:</span></span>
<span class="line"><span>  │   │     INSERT INTO t (name, email) VALUES (?, ?), (?, ?), (?, ?)</span></span>
<span class="line"><span>  │   │     ON DUPLICATE KEY UPDATE name = VALUES(name)</span></span>
<span class="line"><span>  │   ├── PostgresDialect:</span></span>
<span class="line"><span>  │   │     INSERT INTO t (name, email) AS _new VALUES (?, ?), (?, ?), (?, ?)</span></span>
<span class="line"><span>  │   │     ON CONFLICT (email) DO UPDATE SET name = _new.name</span></span>
<span class="line"><span>  │   └── (Non-batch dialects fall back to row-by-row loop)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── em.createNativeQuery(sql).executeUpdate()</span></span>
<span class="line"><span>     → N rows in 1 network round trip (vs N trips for row-by-row)</span></span></code></pre></div><h2 id="security-defense-layers" tabindex="-1">Security Defense Layers <a class="header-anchor" href="#security-defense-layers" aria-label="Permalink to &quot;Security Defense Layers&quot;">​</a></h2><p>The library implements defense-in-depth with multiple security layers:</p><h3 id="layer-1-input-validation-trust-boundary" tabindex="-1">Layer 1: Input Validation (Trust Boundary) <a class="header-anchor" href="#layer-1-input-validation-trust-boundary" aria-label="Permalink to &quot;Layer 1: Input Validation (Trust Boundary)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Lambda Reference</span></span>
<span class="line"><span>  → LambdaUtils.resolveProperty()</span></span>
<span class="line"><span>    → IdentifierValidator.validateColumnName()</span></span>
<span class="line"><span>      → Regex: ^[a-zA-Z_][a-zA-Z0-9_]*$ (ASCII) or Unicode mode</span></span>
<span class="line"><span>      → Unicode homoglyph detection (Cyrillic, Greek, Armenian, fullwidth chars)</span></span>
<span class="line"><span>      → Max length: 128 characters</span></span></code></pre></div><h3 id="layer-2-function-whitelist-code-injection-defense" tabindex="-1">Layer 2: Function Whitelist (Code Injection Defense) <a class="header-anchor" href="#layer-2-function-whitelist-code-injection-defense" aria-label="Permalink to &quot;Layer 2: Function Whitelist (Code Injection Defense)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QuerySpec.func(field, &quot;functionName&quot;, params...)</span></span>
<span class="line"><span>  → Three-tier validation:</span></span>
<span class="line"><span>    1. SAFE_FIELD_NAME_PATTERN regex</span></span>
<span class="line"><span>    2. SAFE_FUNCTION_NAMES set (CONCAT, COALESCE, IFNULL, etc.)</span></span>
<span class="line"><span>    3. BOOLEAN_FUNCTION_NAMES set (IS_NULL, IS_EMPTY, etc.)</span></span>
<span class="line"><span>  → WHITELIST_ENFORCED = true (hardcoded, cannot be disabled)</span></span></code></pre></div><h3 id="layer-3-sql-injection-detection-cte-module" tabindex="-1">Layer 3: SQL Injection Detection (CTE Module) <a class="header-anchor" href="#layer-3-sql-injection-detection-cte-module" aria-label="Permalink to &quot;Layer 3: SQL Injection Detection (CTE Module)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CteSpec.as(sql)</span></span>
<span class="line"><span>  → CTE name reserved word validation</span></span>
<span class="line"><span>  → Dangerous keyword detection (DROP, TRUNCATE, GRANT, etc.), word-boundary matching</span></span>
<span class="line"><span>  → SQL injection pattern detection (comments, semicolons, UNION SELECT, WAITFOR DELAY)</span></span>
<span class="line"><span>  → Unbound parameter detection</span></span>
<span class="line"><span>  → strictMode = true (hardcoded, cannot be disabled)</span></span></code></pre></div><h3 id="layer-4-like-wildcard-escaping" tabindex="-1">Layer 4: LIKE Wildcard Escaping <a class="header-anchor" href="#layer-4-like-wildcard-escaping" aria-label="Permalink to &quot;Layer 4: LIKE Wildcard Escaping&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QuerySpec.like(field, &quot;pattern%_&quot;)</span></span>
<span class="line"><span>  → PredicateHelper.escapeLikeWildcards()</span></span>
<span class="line"><span>    → Escape order: \\ → \\\\, then _ → \\_, then % → \\%</span></span>
<span class="line"><span>    → LIKE escape character: \\</span></span></code></pre></div><h3 id="layer-5-data-sanitization-output" tabindex="-1">Layer 5: Data Sanitization (Output) <a class="header-anchor" href="#layer-5-data-sanitization-output" aria-label="Permalink to &quot;Layer 5: Data Sanitization (Output)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MyJpaPlusException.toString()</span></span>
<span class="line"><span>  → Regex detection: password=, token=, key=, secret=, credential=, ssn, credit_card</span></span>
<span class="line"><span>  → Replace with *** (word-boundary assertions prevent &quot;primaryKey&quot; false positives)</span></span>
<span class="line"><span>  → Truncate to 200 characters</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SqlSanitizer.sanitize(sql)</span></span>
<span class="line"><span>  → Remove: string literals, numeric literals, comments, dollar-quoted strings</span></span>
<span class="line"><span>  → Preserve: LIMIT/OFFSET numbers (for debugging)</span></span>
<span class="line"><span>  → Unicode Private Use Area sentinels during protection</span></span></code></pre></div><h3 id="layer-6-safety-guards-runtime-limits" tabindex="-1">Layer 6: Safety Guards (Runtime Limits) <a class="header-anchor" href="#layer-6-safety-guards-runtime-limits" aria-label="Permalink to &quot;Layer 6: Safety Guards (Runtime Limits)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Query max results:        10,000 rows (configurable)</span></span>
<span class="line"><span>Deep pagination limit:    1,000,000 offset (configurable)</span></span>
<span class="line"><span>Bulk operation rows:      10,000 rows (configurable)</span></span>
<span class="line"><span>IN clause hard limit:     5,000 parameters (configurable)</span></span>
<span class="line"><span>Unconditional operations: Must explicitly pass allowUnconditional(true)</span></span>
<span class="line"><span>Optimistic lock retry:    Max 20 attempts, max 60s total timeout</span></span>
<span class="line"><span>Recursion depth:          NodeResolver=50, CacheKeyBuilder=128</span></span></code></pre></div><h3 id="layer-7-cryptographic-security-encryption" tabindex="-1">Layer 7: Cryptographic Security (Encryption) <a class="header-anchor" href="#layer-7-cryptographic-security-encryption" aria-label="Permalink to &quot;Layer 7: Cryptographic Security (Encryption)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Encrypt fields</span></span>
<span class="line"><span>  → Algorithm: AES/GCM/NoPadding (authenticated encryption, 128-bit tag)</span></span>
<span class="line"><span>  → Key derivation: PBKDF2WithHmacSHA256 (600,000 iterations)</span></span>
<span class="line"><span>  → Multi-version key rotation: v1:key1,v2:key2 format</span></span>
<span class="line"><span>  → Salt verification: Blocks startup if no salt in production</span></span>
<span class="line"><span>  → Plaintext cleanup: Arrays.fill(plaintextBytes, 0) after encryption</span></span>
<span class="line"><span>  → Key material cleanup: Arrays.fill(keyChars, &#39;\\0&#39;) after PBKDF2</span></span></code></pre></div><h2 id="thread-safety-summary" tabindex="-1">Thread Safety Summary <a class="header-anchor" href="#thread-safety-summary" aria-label="Permalink to &quot;Thread Safety Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Thread-Safe</th><th>Mechanism</th></tr></thead><tbody><tr><td>QuerySpec</td><td>No</td><td>Declared as mutable builder</td></tr><tr><td>SubQuerySpec</td><td>No</td><td>Declared as mutable builder</td></tr><tr><td>QueryProjectionSupport</td><td>No</td><td>Delegates to QuerySpec (mutable builder)</td></tr><tr><td>EntityGraphHelper</td><td>No</td><td>Declared as mutable builder</td></tr><tr><td>FunctionWhitelist</td><td>Yes</td><td>ConcurrentHashMap + AtomicReference frozen snapshot</td></tr><tr><td>SoftDeleteContext</td><td>Yes</td><td>ThreadLocal&lt;Integer&gt; counter</td></tr><tr><td>EntityManagerHelper</td><td>Yes</td><td>ConcurrentHashMap + volatile fields</td></tr><tr><td>SoftDeleteBulkExecutor</td><td>Yes</td><td>Stateless (pure static methods, no shared mutable state)</td></tr><tr><td>QueryCacheManager</td><td>Yes</td><td>ConcurrentHashMap + ReentrantLock.tryLock()</td></tr><tr><td>DialectDetector</td><td>Yes</td><td>ConcurrentHashMap cache</td></tr><tr><td>EncryptConverter</td><td>Yes</td><td>ConcurrentLinkedDeque Cipher object pool (bounded, 64 capacity), atomic borrow/return</td></tr><tr><td>InClauseBuilder</td><td>Yes</td><td>AtomicReference&lt;Config&gt;</td></tr><tr><td>LambdaUtils</td><td>Yes</td><td>SampledEvictionCache (ConcurrentHashMap-based)</td></tr><tr><td>IdentifierValidator</td><td>Yes</td><td>Volatile flags (write-once at configuration time)</td></tr><tr><td>SampledEvictionCache</td><td>Yes</td><td>ConcurrentHashMap + tryLock eviction</td></tr></tbody></table>`,29)])])}const y=n(p,[["render",i]]);export{h as __pageData,y as default};
